# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileUploadExample
{
    [ApiController]
    public class FileUploadController : ControllerBase
    {
        [HttpPost("upload")]
        public IActionResult UploadFile()
        {
            try
            {
                var form = Request.Form;
                var file = form["file"];
                if (file == null)
                    return BadRequest();

                // Save the file to the wwwroot/uploads directory
                string uploadPath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads");
                Directory.CreateDirectory(uploadPath);
                var fileName = ContentDispositionHeaderValue.Parse(file.Headers.ContentDisposition).FileName.Trim('"');
                var fullPath = Path.Combine(uploadPath, fileName);
                using (var stream = new FileStream(fullPath, FileMode.Create))
                {
                    file.CopyTo(stream);
                }

                // Return the file path
                return Ok($"{fileName} uploaded successfully");
            }
            catch (Exception ex)
            {
                return BadRequest(ex.Message);
            }
        }
    }
}